-- Parse a flickr.photos.upload.checkTickets response into a map keyed by ticket
-- id. Each entry: { id, complete = 0|1|2|nil, photo_id = "..."|nil, invalid }.
-- Flickr's status attribute is historically named `complete` (0 = processing,
-- 1 = done with a photoid, 2 = conversion failed); we also accept `status` for
-- safety. A ticket Flickr did not recognise carries `invalid="1"`.
function M.parse_upload_tickets(body)
  local tickets = {}
  for attrs in tostring(body or ""):gmatch("<ticket%s+([^>]*)>") do
    local id = attrs:match('id="(.-)"') or attrs:match("id='(.-)'")
    if id and id ~= "" then
      local complete = attrs:match('complete="(.-)"') or attrs:match("complete='(.-)'")
        or attrs:match('status="(.-)"') or attrs:match("status='(.-)'")
      local photoid = attrs:match('photoid="(.-)"') or attrs:match("photoid='(.-)'")
      local invalid = attrs:match('invalid="(.-)"') or attrs:match("invalid='(.-)'")
      tickets[xml_unescape(id)] = {
        id = xml_unescape(id),
        complete = complete and tonumber(complete) or nil,
        photo_id = (photoid and photoid ~= "") and xml_unescape(photoid) or nil,
        invalid = invalid ~= nil and invalid ~= "" and invalid ~= "0",
      }
    end
  end
  return tickets
end

-- Check the status of one or more asynchronous upload tickets. Unauthenticated
-- (uses the public API key), so it is an idempotent read safe to poll/retry.
function M.upload_check_tickets(api_key, ticket_ids)
  if type(ticket_ids) == "table" then ticket_ids = table.concat(ticket_ids, ",") end
  ticket_ids = tostring(ticket_ids or "")
  if ticket_ids == "" then return nil, "missing upload ticket id(s)" end

  local body, err = M.public_call(api_key, "flickr.photos.upload.checkTickets", {
    tickets = ticket_ids,
  })
  if not body then return nil, err end
  return M.parse_upload_tickets(body), body
end

return M
end

package.preload["dtrmflickr.state"] = function(...)
-- state.lua — per-image Flickr publish state.
--
-- This is the only module that knows how state is persisted. The current
-- backend is image tags because they are Lua-writable, per-image, multi-valued,
-- and survive through XMP sidecars when sidecars are enabled.

local dt = require "darktable"

local M = {}

local PREFIX <const> = "dtrmflickr"

local function tag_name(tag)
  return tag and tag.name or nil
end

local function photo_tag(account_nsid, photo_id)
  return table.concat({ PREFIX, tostring(account_nsid), tostring(photo_id) }, "|")
end

local function set_tag(account_nsid, set_id)
  return table.concat({ PREFIX, tostring(account_nsid), "set", tostring(set_id) }, "|")
end

local function published_tag(account_nsid, kind, stamp)
  if kind == nil then return table.concat({ PREFIX, tostring(account_nsid), "published", tostring(stamp) }, "|") end
  return table.concat({ PREFIX, tostring(account_nsid), "published", tostring(kind), tostring(stamp) }, "|")
end

local function needs_republish_tag(account_nsid)
  return table.concat({ PREFIX, tostring(account_nsid), "needs-republish" }, "|")
end

local function reason_tag(account_nsid, reason)
  return table.concat({ PREFIX, tostring(account_nsid), "reason", tostring(reason) }, "|")
end

local function fingerprint_tag(account_nsid, field, fingerprint)
  return table.concat({ PREFIX, tostring(account_nsid), "fingerprint", tostring(field), tostring(fingerprint) }, "|")
end

local function valid_component(value)
  value = tostring(value or "")
  return value ~= "" and value:find("|", 1, true) == nil
end

local function assert_component(kind, value)
  assert(valid_component(value), "invalid Flickr " .. kind)
end

local function is_reserved_account_component(value)
  return value == "set" or value == "published" or value == "needs-republish" or value == "reason"
end

local function ensure_tag(name)
  return dt.tags.find(name) or dt.tags.create(name)
end

local function image_tags(image)
  if image and image.get_tags then return image:get_tags() end
  return dt.tags.get_tags(image)
end

local function attach(image, tag)
  if image and image.attach_tag then return image:attach_tag(tag) end
  return dt.tags.attach(tag, image)
end

local function detach(image, tag)
  if image and image.detach_tag then return image:detach_tag(tag) end
  return dt.tags.detach(tag, image)
end

function M.is_plugin_tag(name)
  return type(name) == "string" and (name == PREFIX or name:sub(1, #PREFIX + 1) == PREFIX .. "|")
end

function M.now_stamp()
  return os.date("!%Y%m%dT%H%M%SZ")
end

local function normalize_stamp(value)
  value = tostring(value or ""):match("^%s*(.-)%s*$")
  if value == "" then return nil end
  local y, mo, d, h, mi, s = value:match("^(%d%d%d%d)(%d%d)(%d%d)T(%d%d)(%d%d)(%d%d)Z$")
  if y then return y .. mo .. d .. h .. mi .. s end
  y, mo, d, h, mi, s = value:match("^(%d%d%d%d)[:%-](%d%d)[:%-](%d%d)%s+(%d%d):(%d%d):(%d%d)")
  if y then return y .. mo .. d .. h .. mi .. s end
  return nil
end
M.normalize_stamp = normalize_stamp

local function stamp_is_newer(a, b)
  local na = normalize_stamp(a)
  local nb = normalize_stamp(b)
  if not na or not nb then return false end
  return na > nb
end
M.stamp_is_newer = stamp_is_newer

local function compact_stamp(value)
  local n = normalize_stamp(value)
  if not n then return nil end
  return n:sub(1, 8) .. "T" .. n:sub(9, 14) .. "Z"
end
M.compact_stamp = compact_stamp

function M.get_photo_id(image, account_nsid)
  local prefix = PREFIX .. "|" .. tostring(account_nsid) .. "|"
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    local id = name and name:sub(1, #prefix) == prefix and name:sub(#prefix + 1) or nil
    if id and id ~= "" and not id:find("|", 1, true) and not is_reserved_account_component(id) then return id end
  end
  return nil
end

function M.get_any_photo_id(image)
  local prefix = PREFIX .. "|"
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    if name and name:sub(1, #prefix) == prefix then
      local rest = name:sub(#prefix + 1)
      local account_nsid, photo_id = rest:match("^([^|]+)|([^|]+)$")
      if account_nsid and photo_id and not is_reserved_account_component(photo_id) then return account_nsid, photo_id end
    end
  end
  return nil, nil
end

local function valid_publish_kind(kind)
  return kind == "image" or kind == "metadata"
end

local function latest_published_at(image, account_nsid, kind)
  local prefix = PREFIX .. "|" .. tostring(account_nsid) .. "|published|"
  local latest
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    local rest = name and name:sub(1, #prefix) == prefix and name:sub(#prefix + 1) or nil
    local stamp
    if rest then
      if kind then
        stamp = rest:match("^" .. kind .. "|(.+)$")
      else
        local tag_kind, tag_stamp = rest:match("^([^|]+)|(.+)$")
        if valid_publish_kind(tag_kind) then stamp = tag_stamp else stamp = rest end
      end
    end
    if stamp and normalize_stamp(stamp) and (not latest or stamp_is_newer(stamp, latest)) then latest = stamp end
  end
  return latest
end

function M.get_published_at(image, account_nsid, kind)
  if kind then
    return latest_published_at(image, account_nsid, kind)
  end
  return latest_published_at(image, account_nsid, "image")
    or latest_published_at(image, account_nsid, nil)
end

function M.get_image_published_at(image, account_nsid)
  return M.get_published_at(image, account_nsid, "image")
end

function M.get_metadata_published_at(image, account_nsid)
  return M.get_published_at(image, account_nsid, "metadata")
end

function M.clear_published_at(image, account_nsid, kind)
  assert_component("account id", account_nsid)
  local prefix = PREFIX .. "|" .. tostring(account_nsid) .. "|published|"
  local removed = 0
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    local rest = name and name:sub(1, #prefix) == prefix and name:sub(#prefix + 1) or nil
    local matches = false
    if rest then
      if kind == nil then
        matches = true
      else
        matches = rest:sub(1, #kind + 1) == kind .. "|"
      end
    end
    if matches then
      detach(image, tag)
      removed = removed + 1
    end
  end
  return removed
end

local function set_published_kind_at(image, account_nsid, kind, stamp)
  assert_component("account id", account_nsid)
  assert(valid_publish_kind(kind), "invalid Flickr published kind")
  stamp = stamp or M.now_stamp()
  stamp = compact_stamp(stamp)
  assert(stamp, "invalid Flickr published stamp")
  M.clear_published_at(image, account_nsid, kind)
  attach(image, ensure_tag(published_tag(account_nsid, kind, stamp)))
  return stamp
end

function M.set_image_published_at(image, account_nsid, stamp)
  local result = set_published_kind_at(image, account_nsid, "image", stamp)
  M.clear_reason(image, account_nsid, "image")
  return result
end

function M.set_metadata_published_at(image, account_nsid, stamp)
  return set_published_kind_at(image, account_nsid, "metadata", stamp)
end

function M.set_published_at(image, account_nsid, stamp)
  stamp = stamp or M.now_stamp()
  stamp = compact_stamp(stamp)
  assert(stamp, "invalid Flickr published stamp")
  M.set_image_published_at(image, account_nsid, stamp)
  M.set_metadata_published_at(image, account_nsid, stamp)
  M.clear_metadata_reasons(image, account_nsid)
  M.clear_needs_republish(image, account_nsid)
  return stamp
end

function M.mark_reason(image, account_nsid, reason)
  assert_component("account id", account_nsid)
  assert_component("reason", reason)
  attach(image, ensure_tag(reason_tag(account_nsid, reason)))
  attach(image, ensure_tag(needs_republish_tag(account_nsid)))
end

function M.clear_reason(image, account_nsid, reason)
  assert_component("account id", account_nsid)
  assert_component("reason", reason)
  local tag = dt.tags.find(reason_tag(account_nsid, reason))
  if not tag then return false end
  detach(image, tag)
  if #M.get_reasons(image, account_nsid) == 0 then M.clear_needs_republish(image, account_nsid) end
  return true
end

local metadata_reasons = {
  keywords = true,
  title_description = true,
  gps = true,
  date_taken = true,
  visibility = true,
  safety = true,
  content_type = true,
  license = true,
  permissions = true,
}

local function known_metadata_reasons()
  local reasons = {}
  for reason in pairs(metadata_reasons) do reasons[#reasons + 1] = reason end
  table.sort(reasons)
  return reasons
end
M.metadata_reasons = known_metadata_reasons

function M.is_metadata_reason(reason)
  return metadata_reasons[tostring(reason or "")] == true
end

function M.classify_reasons(reasons)
  local has_image = false
  local has_metadata = false
  for _, reason in ipairs(reasons or {}) do
    if reason == "image" then has_image = true
    elseif M.is_metadata_reason(reason) then has_metadata = true
    else has_metadata = true end
  end
  if has_image and has_metadata then return "both" end
  if has_image then return "image" end
  if has_metadata then return "metadata" end
  return "none"
end

function M.clear_metadata_reasons(image, account_nsid)
  local removed = 0
  for reason in pairs(metadata_reasons) do
    if M.clear_reason(image, account_nsid, reason) then removed = removed + 1 end
  end
  return removed
end

local function fingerprint_prefix(account_nsid, field)
  return PREFIX .. "|" .. tostring(account_nsid) .. "|fingerprint|" .. tostring(field) .. "|"
end

function M.get_fingerprint(image, account_nsid, field)
  local prefix = fingerprint_prefix(account_nsid, field)
  local latest
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    local value = name and name:sub(1, #prefix) == prefix and name:sub(#prefix + 1) or nil
    if valid_component(value) then latest = value end
  end
  return latest
end

function M.clear_fingerprint(image, account_nsid, field)
  assert_component("account id", account_nsid)
  assert_component("fingerprint field", field)
  local prefix = fingerprint_prefix(account_nsid, field)
  local removed = 0
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    if name and name:sub(1, #prefix) == prefix then
      detach(image, tag)
      removed = removed + 1
    end
  end
  return removed
end

function M.set_fingerprint(image, account_nsid, field, fingerprint)
  assert_component("account id", account_nsid)
  assert_component("fingerprint field", field)
  assert_component("fingerprint", fingerprint)
  M.clear_fingerprint(image, account_nsid, field)
  attach(image, ensure_tag(fingerprint_tag(account_nsid, field, fingerprint)))
  return fingerprint
end

function M.set_fingerprints(image, account_nsid, fingerprints)
  local changed = 0
  for field, fingerprint in pairs(fingerprints or {}) do
    if fingerprint ~= nil then
      M.set_fingerprint(image, account_nsid, field, fingerprint)
      changed = changed + 1
    end
  end
  return changed
end

function M.metadata_fingerprint_reasons(image, account_nsid, fingerprints)
  local reasons = {}
  for _, reason in ipairs(known_metadata_reasons()) do
    local current = fingerprints and fingerprints[reason] or nil
    if current ~= nil then
      local previous = M.get_fingerprint(image, account_nsid, reason)
      if previous and previous ~= tostring(current) then reasons[#reasons + 1] = reason end
    end
  end
  table.sort(reasons)
  return reasons
end

function M.get_reasons(image, account_nsid)
  local prefix = PREFIX .. "|" .. tostring(account_nsid) .. "|reason|"
  local reasons = {}
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    local reason = name and name:sub(1, #prefix) == prefix and name:sub(#prefix + 1) or nil
    if valid_component(reason) then reasons[#reasons + 1] = reason end
  end
  table.sort(reasons)
  return reasons
end

function M.mark_needs_republish(image, account_nsid)
  M.mark_reason(image, account_nsid, "image")
end

function M.clear_needs_republish(image, account_nsid)
  assert_component("account id", account_nsid)
  local removed = false
  local reason_prefix = PREFIX .. "|" .. tostring(account_nsid) .. "|reason|"
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    if name and name:sub(1, #reason_prefix) == reason_prefix then
      detach(image, tag)
      removed = true
    end
  end
  local tag = dt.tags.find(needs_republish_tag(account_nsid))
  if tag then
    detach(image, tag)
    removed = true
  end
  return removed
end

function M.needs_republish(image, account_nsid)
  local name = needs_republish_tag(account_nsid)
  local reason_prefix = PREFIX .. "|" .. tostring(account_nsid) .. "|reason|"
  for _, tag in ipairs(image_tags(image) or {}) do
    local tagname = tag_name(tag)
    if tagname == name then return true end
    if tagname and tagname:sub(1, #reason_prefix) == reason_prefix then return true end
  end
  return false
end

function M.evaluate_publish_state(image, account_nsid, opts)
  opts = opts or {}
  local photo_id = M.get_photo_id(image, account_nsid)
  if not photo_id then return "unpublished", nil, nil end

  local image_published_at = M.get_image_published_at(image, account_nsid)
  local metadata_published_at = M.get_metadata_published_at(image, account_nsid)
  local published_at = image_published_at or metadata_published_at or M.get_published_at(image, account_nsid)
  local reasons = M.get_reasons(image, account_nsid)
  if #reasons > 0 or M.needs_republish(image, account_nsid) then
    return "needs-republish", published_at, photo_id, reasons
  end
  if not published_at then
    return "unknown", published_at, photo_id, reasons
  end

  local changed_at = image and image.change_timestamp or nil
  local newest_handled_at = image_published_at
  if metadata_published_at and (not newest_handled_at or stamp_is_newer(metadata_published_at, newest_handled_at)) then
    newest_handled_at = metadata_published_at
  end
  if changed_at and newest_handled_at and stamp_is_newer(changed_at, newest_handled_at) then
    local metadata_requeue = M.metadata_fingerprint_reasons(image, account_nsid, opts.metadata_fingerprints)
    if #metadata_requeue > 0 then
      for _, reason in ipairs(metadata_requeue) do M.mark_reason(image, account_nsid, reason) end
      return "needs-republish", published_at, photo_id, M.get_reasons(image, account_nsid)
    end
    M.mark_needs_republish(image, account_nsid)
    return "needs-republish", published_at, photo_id, M.get_reasons(image, account_nsid)
  end

  M.clear_needs_republish(image, account_nsid)
  return "current", published_at, photo_id, reasons
end

function M.set_photo_id(image, account_nsid, photo_id)
  assert_component("account id", account_nsid)
  assert_component("photo id", photo_id)
  local old_id = M.get_photo_id(image, account_nsid)
  if old_id and old_id ~= tostring(photo_id) then
    local old_tag = dt.tags.find(photo_tag(account_nsid, old_id))
    if old_tag then detach(image, old_tag) end
  end
  attach(image, ensure_tag(photo_tag(account_nsid, photo_id)))
end

function M.clear_photo_id(image, account_nsid)
  assert_component("account id", account_nsid)
  local old_id = M.get_photo_id(image, account_nsid)
  if not old_id then return false end
  local old_tag = dt.tags.find(photo_tag(account_nsid, old_id))
  if old_tag then detach(image, old_tag) end
  M.clear_published_at(image, account_nsid)
  M.clear_needs_republish(image, account_nsid)
  for _, reason in ipairs(known_metadata_reasons()) do M.clear_fingerprint(image, account_nsid, reason) end
  return true
end

function M.get_sets(image, account_nsid)
  assert_component("account id", account_nsid)
  local prefix = PREFIX .. "|" .. tostring(account_nsid) .. "|set|"
  local sets = {}
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    local id = name and name:sub(1, #prefix) == prefix and name:sub(#prefix + 1) or nil
    if valid_component(id) then sets[#sets + 1] = id end
  end
  table.sort(sets)
  return sets
end

function M.add_set(image, account_nsid, set_id)
  assert_component("account id", account_nsid)
  assert_component("set id", set_id)
  attach(image, ensure_tag(set_tag(account_nsid, set_id)))
end

function M.remove_set(image, account_nsid, set_id)
  assert_component("account id", account_nsid)
  assert_component("set id", set_id)
  local tag = dt.tags.find(set_tag(account_nsid, set_id))
  if tag then detach(image, tag) end
end

function M.clear_sets(image, account_nsid)
  local removed = 0
  for _, set_id in ipairs(M.get_sets(image, account_nsid)) do
    M.remove_set(image, account_nsid, set_id)
    removed = removed + 1
  end
  return removed
end

function M.clear_account(image, account_nsid)
  local removed = M.clear_sets(image, account_nsid)
  removed = removed + M.clear_published_at(image, account_nsid)
  if M.clear_needs_republish(image, account_nsid) then removed = removed + 1 end
  if M.clear_photo_id(image, account_nsid) then removed = removed + 1 end
  return removed
end

function M.clear_other_accounts(image, keep_account_nsid)
  local keep = tostring(keep_account_nsid)
  local accounts = {}
  local prefix = PREFIX .. "|"
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    if name and name:sub(1, #prefix) == prefix then
      local account_nsid = name:sub(#prefix + 1):match("^([^|]+)|")
      if account_nsid and account_nsid ~= keep then accounts[account_nsid] = true end
    end
  end
  local removed = 0
  for account_nsid in pairs(accounts) do
    removed = removed + M.clear_account(image, account_nsid)
  end
  return removed
end

return M
end

package.preload["dtrmflickr.metadata"] = function(...)
local dt = require "darktable"
local state = require "dtrmflickr.state"

local M = {}

local TAG_FLAG_CATEGORY <const> = 1
local TAG_FLAG_PRIVATE <const> = 2

function M.image_title(image, filename)
  if image and image.title and image.title ~= "" then return image.title end
  if image and image.filename and image.filename ~= "" then return image.filename end
  return tostring(filename or ""):match("[^/\\]+$") or tostring(filename or "")
end

function M.image_date_taken(image)
  local value = image and image.exif_datetime_taken or nil
  value = value and tostring(value):match("^%s*(.-)%s*$") or nil
  if not value or value == "" then return nil end
  local y, mo, d, h, mi, s = value:match("^(%d%d%d%d)[:%-](%d%d)[:%-](%d%d)%s+(%d%d):(%d%d):(%d%d)")
  if not y then return nil end
  -- Flickr date_taken is a timezone-less taken-local-time field. Do not convert
  -- from darktable's EXIF taken time; just normalize to MySQL datetime syntax.
  return string.format("%s-%s-%s %s:%s:%s", y, mo, d, h, mi, s)
end

local function flickr_coordinate(value, min_value, max_value)
  local n = tonumber(value)
  if not n or n ~= n or n < min_value or n > max_value then return nil end
  return string.format("%.6f", n)
end

function M.image_location(image)
  local lat = flickr_coordinate(image and image.latitude or nil, -90, 90)
  local lon = flickr_coordinate(image and image.longitude or nil, -180, 180)
  if lat == nil or lon == nil then return nil, nil end
  return lat, lon
end

local function image_tags(image)
  local tags = {}
  if image and image.get_tags then
    tags = image:get_tags() or {}
  else
    tags = dt.tags.get_tags(image) or {}
  end
  table.sort(tags, function(a, b) return tostring(a and a.name or "") < tostring(b and b.name or "") end)
  return tags
end

function M.image_tag_names(image)
  local names = {}
  for _, tag in ipairs(image_tags(image)) do
    local name = tag and tag.name or nil
    if name and name ~= "" then names[#names + 1] = name end
  end
  return names
end

function M.tag_matches_filter(tag_name, filter)
  filter = tostring(filter or ""):match("^%s*(.-)%s*$"):lower()
  if filter == "" then return false end
  return tostring(tag_name or ""):lower():find(filter, 1, true) ~= nil
end

local function flickr_quote_tag(tag)
  tag = tostring(tag or "")
  if tag:find("%s") then return '"' .. tag .. '"' end
  return tag
end

local function publish_tag_name(name)
  name = tostring(name or ""):match("^%s*(.-)%s*$")
  local leaf = name:match("([^|]+)$")
  leaf = leaf and leaf:match("^%s*(.-)%s*$") or name
  leaf = leaf:gsub('"', ""):match("^%s*(.-)%s*$")
  return leaf ~= "" and leaf or nil
end

local function tag_flags(tag)
  return tonumber(tag and tag.flags or 0) or 0
end

local function tag_is_private_or_category(tag)
  local flags = tag_flags(tag)
  return (flags & (TAG_FLAG_PRIVATE | TAG_FLAG_CATEGORY)) ~= 0
end

local function has_private_category_parent(name)
  name = tostring(name or "")
  local parent = name:match("^(.*)|[^|]+$")
  while parent and parent ~= "" do
    local parent_tag = dt.tags and dt.tags.find and dt.tags.find(parent) or nil
    local flags = tag_flags(parent_tag)
    if (flags & (TAG_FLAG_PRIVATE | TAG_FLAG_CATEGORY)) == (TAG_FLAG_PRIVATE | TAG_FLAG_CATEGORY) then
      return true
    end
    parent = parent:match("^(.*)|[^|]+$")
  end
  return false
end

local function tag_is_publishable_keyword(tag)
  local name = tag and tag.name or nil
  if not name or name == "" then return false end
  if state.is_plugin_tag(name) or name:match("^darktable|") ~= nil then return false end
  if tag_is_private_or_category(tag) then return false end
  if has_private_category_parent(name) then return false end
  return true
end

function M.image_keyword_tags(image, excluded_filters, tag_names, opts)
  opts = opts or {}
  local tags = {}
  local seen = {}
  local source_tags = {}
  if tag_names then
    for _, name in ipairs(tag_names) do
      source_tags[#source_tags + 1] = (dt.tags and dt.tags.find and dt.tags.find(name)) or { name = name }
    end
  else
    source_tags = image_tags(image)
  end
  table.sort(source_tags, function(a, b) return tostring(a and a.name or "") < tostring(b and b.name or "") end)

  for _, tag in ipairs(source_tags) do
    local name = tag and tag.name or nil
    if name and name ~= "" then
      local excluded = not tag_is_publishable_keyword(tag)
      for _, filter in ipairs(excluded_filters or {}) do
        if M.tag_matches_filter(name, filter) then excluded = true; break end
      end
      if not excluded then
        local publish_name = publish_tag_name(name)
        local key = publish_name and publish_name:lower() or nil
        if publish_name and not seen[key] then
          seen[key] = true
          tags[#tags + 1] = publish_name
        end
      end
    end
  end

  table.sort(tags, function(a, b) return tostring(a):lower() < tostring(b):lower() end)
  local original_count = #tags
  if opts.max_tags and #tags > opts.max_tags then
    local limited = {}
    for i = 1, opts.max_tags do limited[i] = tags[i] end
    tags = limited
  end

  local encoded = {}
  for _, tag in ipairs(tags) do encoded[#encoded + 1] = flickr_quote_tag(tag) end
  return #encoded > 0 and table.concat(encoded, " ") or nil, math.max(0, original_count - #tags)
end

local function fingerprint_hash(value)
  local s = tostring(value == nil and "" or value)
  local h = 2166136261
  for i = 1, #s do
    h = (h ~ s:byte(i)) * 16777619 % 4294967296
  end
  return string.format("%08x", h)
end

local function fingerprint_parts(parts)
  return fingerprint_hash(table.concat(parts or {}, "\31"))
end

function M.fingerprints_from_values(values)
  values = values or {}
  local privacy = values.privacy or {}
  local safety = values.safety or {}
  local content_type = values.content_type or {}
  local license = values.license or {}
  local permissions = values.permissions or {}
  local fingerprints = {}
  if values.include_keywords or values.tags ~= nil then
    fingerprints.keywords = fingerprint_hash(values.tags or "")
  end
  if values.include_title_description or values.title ~= nil or values.description ~= nil then
    fingerprints.title_description = fingerprint_parts({ values.title or "", values.description or "" })
  end
  if values.include_gps or values.lat ~= nil or values.lon ~= nil then
    fingerprints.gps = fingerprint_parts({ values.lat or "", values.lon or "" })
  end
  if values.include_date_taken or values.date_taken ~= nil then
    fingerprints.date_taken = fingerprint_hash(values.date_taken or "")
  end
  if values.privacy ~= nil then
    fingerprints.visibility = fingerprint_parts({ privacy.is_public or "", privacy.is_friend or "", privacy.is_family or "" })
  end
  if values.safety ~= nil then
    fingerprints.safety = fingerprint_hash(safety.flickr_value or "")
  end
  if values.content_type ~= nil then
    fingerprints.content_type = fingerprint_hash(content_type.flickr_value or "")
  end
  if values.license ~= nil then
    fingerprints.license = fingerprint_hash(license.flickr_value or "")
  end
  if values.permissions ~= nil then
    fingerprints.permissions = fingerprint_parts({ permissions.perm_comment or "", permissions.perm_addmeta or "" })
  end
  return fingerprints
end

return M
end

package.preload["dtrmflickr.claim"] = function(...)
local dt = require "darktable"
local rest = require "dtrmflickr.flickr_rest"
local state = require "dtrmflickr.state"
local metadata = require "dtrmflickr.metadata"
local queue = require "dtrmflickr.queue"

local M = {}

local function remote_attr(body, name)
  return body and (body:match(name .. '="(.-)"') or body:match(name .. "='(.-)'")) or nil
end

local function xml_unescape(s)
  return tostring(s or "")
    :gsub("&#x(%x+);", function(h)
      local n = tonumber(h, 16)
      if not n then return "" end
      local ok, c = pcall(utf8.char, n)
      return ok and c or ""
    end)
    :gsub("&#(%d+);", function(d)
      local n = tonumber(d, 10)
      if not n then return "" end
      local ok, c = pcall(utf8.char, n)
      return ok and c or ""
    end)
    :gsub("&quot;", '"')
    :gsub("&apos;", "'")
    :gsub("&lt;", "<")
    :gsub("&gt;", ">")
    :gsub("&amp;", "&")
end

local function filename_part(value)
  return tostring(value or ""):match("[^/\\]+$") or tostring(value or "")
end

local function basename_part(value)
  local file = filename_part(value)
  return file:match("^(.*)%.[^%.]+$") or file
end

local function normalize_match_text(value)
  value = xml_unescape(value or ""):lower()
  value = value:gsub("^%s+", ""):gsub("%s+$", "")
  return value
end

function M.claim_match_terms(image)
  local terms, seen = {}, {}
  local function add(value)
    value = normalize_match_text(value)
    if value ~= "" and not seen[value] then
      seen[value] = true
      terms[#terms + 1] = value
    end
  end
  add(image and image.filename)
  add(basename_part(image and image.filename))
  add(image and image.title)
  add(basename_part(image and image.title))
  if image and dt.metadata and type(dt.metadata.exists) == "function" then
    local ok_exists, exists = pcall(dt.metadata.exists, "Xmp.xmpMM.PreservedFileName")
    if ok_exists and exists then
      local ok_value, preserved = pcall(function() return image["preserved filename"] end)
      if ok_value and type(preserved) == "string" then
        preserved = preserved:match("^%s*(.-)%s*$")
        add(preserved)
        add(basename_part(preserved))
      end
    end
  end
  return terms
end

function M.parse_search_photos(body)
  local photos = {}
  for attrs in tostring(body or ""):gmatch("<photo%s+([^>]-)/>") do
    photos[#photos + 1] = {
      id = remote_attr(attrs, "id"),
      title = xml_unescape(remote_attr(attrs, "title") or ""),
      datetaken = remote_attr(attrs, "datetaken"),
      dateupload = remote_attr(attrs, "dateupload"),
    }
  end
  for attrs in tostring(body or ""):gmatch("<photo%s+([^>]-)>") do
    if not attrs:match("/%s*$") then
      photos[#photos + 1] = {
        id = remote_attr(attrs, "id"),
        title = xml_unescape(remote_attr(attrs, "title") or ""),
        datetaken = remote_attr(attrs, "datetaken"),
        dateupload = remote_attr(attrs, "dateupload"),
      }
    end
  end
  return photos
end

local function add_candidate(candidates, photo, reason)
  if not photo or not photo.id or photo.id == "" then return end
  local current = candidates[photo.id]
  if not current then
    candidates[photo.id] = {
      id = photo.id,
      title = photo.title,
      datetaken = photo.datetaken,
      dateupload = photo.dateupload,
      reasons = {},
    }
    current = candidates[photo.id]
  end
  current.reasons[reason] = true
end

local function candidate_list(candidates)
  local list = {}
  for _, item in pairs(candidates or {}) do list[#list + 1] = item end
  table.sort(list, function(a, b) return tostring(a.id) < tostring(b.id) end)
  return list
end

local function candidate_title_matches(candidate, terms)
  local title = normalize_match_text(candidate and candidate.title)
  if title == "" then return false end
  local title_base = normalize_match_text(basename_part(title))
  for _, term in ipairs(terms or {}) do
    if title == term or title_base == term then return true end
  end
  return false
end

local function search_existing_candidates(api_key, api_secret, acc, image)
  local candidates, errors = {}, {}
  local transient = nil
  local terms = M.claim_match_terms(image)
  local taken = metadata.image_date_taken(image)

  local function run_search(args, reason)
    args = args or {}
    args.user_id = acc.nsid
    args.media = "photos"
    args.extras = "date_taken,date_upload,original_format"
    local bodies, err = rest.photos_search_all(api_key, api_secret, acc, args, { per_page = 50 })
    if not bodies then
      errors[#errors + 1] = tostring(err)
      -- Remember the first transient/rate-limit failure so the caller can ask
      -- the shared queue to retry the whole claim instead of concluding "no
      -- match" from an incomplete candidate set.
      if not transient and queue.is_retryable(err) then transient = tostring(err) end
      return
    end
    for _, body in ipairs(bodies) do
      for _, photo in ipairs(M.parse_search_photos(body)) do
        add_candidate(candidates, photo, reason)
      end
    end
  end

  if taken then
    run_search({ min_taken_date = taken, max_taken_date = taken, sort = "date-taken-desc" }, "taken")
  end
  for _, term in ipairs(terms) do
    run_search({ text = term, sort = "relevance" }, "text")
  end

  return candidate_list(candidates), terms, taken, errors, transient
end

function M.choose_existing_match(candidates, terms, taken)
  local exact_date = {}
  if taken then
    for _, candidate in ipairs(candidates or {}) do
      if candidate.datetaken == taken or candidate.reasons.taken then exact_date[#exact_date + 1] = candidate end
    end
    if #exact_date == 1 then return exact_date[1], "exact date/time" end
  end

  local title_matches = {}
  for _, candidate in ipairs(candidates or {}) do
    if candidate_title_matches(candidate, terms) and (not taken or candidate.datetaken == taken or candidate.reasons.taken) then
      title_matches[#title_matches + 1] = candidate
    end
  end
  if #title_matches == 1 then
    return title_matches[1], taken and "title/filename + date/time" or "title/filename"
  end

  if #exact_date > 1 then return nil, "ambiguous exact date/time" end
  if #title_matches > 1 then return nil, "ambiguous title/filename" end
  return nil, #candidates > 0 and "no strong unique match" or "no match"
end

function M.claim_existing_for_image(api_key, api_secret, acc, image)
  if state.get_photo_id(image, acc.nsid) then return "skipped", "already linked" end
  local candidates, terms, taken, errors, transient = search_existing_candidates(api_key, api_secret, acc, image)
  local match, reason = M.choose_existing_match(candidates, terms, taken)
  if match then
    state.set_photo_id(image, acc.nsid, match.id)
    return "claimed", string.format("%s (%s)", tostring(match.id), reason)
  end
  -- A transient/rate-limit failure left the candidate set incomplete, so any
  -- "no match"/"skipped"/"ambiguous" verdict here is unreliable. Surface a
  -- (nil, err) failure so the queued job retries the whole claim with backoff
  -- instead of permanently mislinking nothing.
  if transient then return nil, transient end
  if #errors > 0 and #candidates == 0 then return "error", table.concat(errors, "; ") end
  return "skipped", reason
end

return M
end

package.preload["dtrmflickr.queue"] = function(...)
-- queue.lua — small serial scheduler for Flickr API work.
--
-- darktable Lua callbacks are synchronous, but keeping every Flickr operation
-- behind one scheduler gives us one place for pacing, retries/backoff,
-- coalescing, and stale UI checks. Jobs normally run immediately; if a callback
-- enqueues more work while the queue is active, duplicate coalesced pending jobs
-- are replaced.

local M = {}

-- NOTE: os.clock() is wall-clock on Windows (the shipping target) but CPU time
-- on POSIX, so on non-Windows hosts method pacing over-waits (it never sees the
-- real time elapsed during a network/sleep). Hosts that need accurate pacing
-- elsewhere can inject a wall-clock `now_ms` via M.new{ now_ms = ... }.
local function monotonic_ms()
  return math.floor((os.clock() or 0) * 1000)
end

-- Unpack a packed result table preserving exact arity, including nil holes and
-- a trailing nil. Plain table.unpack relies on the ambiguous `#` border and can
-- drop values after an interior nil (e.g. memberships, nil, sets).
local function unpack_result(result)
  if not result then return end
  return table.unpack(result, 1, result.n or #result)
end

local function sleep_ms(sleep_fn, ms)
  if sleep_fn and ms and ms > 0 then sleep_fn(ms) end
end

local function default_retryable(err)
  local s = tostring(err or ""):lower()
  if s == "" then return false end
  if s:find("rate", 1, true) and s:find("limit", 1, true) then return true, "rate-limit" end
  if s:find("too many", 1, true) or s:find("throttle", 1, true) then return true, "rate-limit" end
  if s:find("http 429", 1, true) or s:find("(429)", 1, true) then return true, "rate-limit" end
  -- Flickr REST error 105 is the documented "service currently unavailable"
  -- overload / soft-throttle signal — the REST-body sibling of an HTTP 429 and
  -- the most common transient REST failure under load. Its message text
  -- ("Service currently unavailable") contains none of the substrings matched
  -- below (note: "currently", not "temporarily", so the "temporar" rule misses
  -- it), so match the code and the phrase explicitly and back off like a rate
  -- limit. Sibling of the (106) "write operation failed" rule below.
  if s:find("(105)", 1, true) or s:find("service currently unavailable", 1, true)
    or s:find("service unavailable", 1, true) or s:find("temporarily unavailable", 1, true) then
    return true, "rate-limit"
  end
  if s:find("temporar", 1, true) or s:find("timed out", 1, true) or s:find("timeout", 1, true) then return true, "transient" end
  if s:find("connection", 1, true) or s:find("network", 1, true) or s:find("curl", 1, true) then return true, "transient" end
  if s:find("write operation failed", 1, true) or s:find("(106)", 1, true) then return true, "transient" end
  if s:find("empty flickr", 1, true) then return true, "transient" end
  return false
end

-- Exposed so multi-call helpers (e.g. claim's fan-out of searches inside one
-- queue job) can classify a transient/rate-limit failure and choose to surface
-- it as a retryable `nil, err` instead of swallowing it into a status string.
function M.is_retryable(err)
  return default_retryable(err)
end

local function backoff_delay_ms(job, attempt, reason)
  local base = tonumber(job.retry_base_ms) or 0
  if reason == "rate-limit" and job.rate_limit_base_ms then
    base = tonumber(job.rate_limit_base_ms) or base
  end
  if base <= 0 then return 0 end
  local delay = base * (2 ^ math.max(0, attempt - 1))
  local max_delay = tonumber(job.retry_max_ms) or 0
  if max_delay > 0 and delay > max_delay then delay = max_delay end
  local jitter = job.jitter_ms
  if type(jitter) == "function" then
    delay = delay + (tonumber(jitter(delay, attempt, reason)) or 0)
  elseif jitter then
    local amount = tonumber(jitter) or 0
    if amount > 0 then delay = delay + math.random(0, amount) end
  end
  if delay < 0 then delay = 0 end
  return math.floor(delay)
end

local Queue = {}
Queue.__index = Queue

local function copy_list(list)
  local out = {}
  for i, item in ipairs(list or {}) do
    if type(item) == "table" then
      local copied = {}
      for k, v in pairs(item) do copied[k] = v end
      out[i] = copied
    else
      out[i] = item
    end
  end
  return out
end

function M.new(opts)
  opts = opts or {}
  return setmetatable({
    pending = {},
    running = false,
    last_started = {},
    recent = {},
    sequence = 0,
    now_ms = opts.now_ms or monotonic_ms,
    sleep_ms = opts.sleep_ms,
    on_wait = opts.on_wait,
    on_event = opts.on_event,
    default_pace_ms = opts.default_pace_ms or 0,
    method_pace_ms = opts.method_pace_ms or {},
    default_max_attempts = opts.default_max_attempts or 1,
    retry_base_ms = opts.retry_base_ms or 0,
    retry_max_ms = opts.retry_max_ms or 0,
    rate_limit_base_ms = opts.rate_limit_base_ms,
    retryable = opts.retryable or default_retryable,
    recent_limit = math.max(0, tonumber(opts.recent_limit) or 25),
    stats = {
      enqueued = 0, started = 0, succeeded = 0, coalesced = 0, stale = 0,
      failed = 0, retried = 0, rate_limited = 0, waited_ms = 0, waits = 0,
    },
  }, Queue)
end

function Queue:emit(event, job, fields)
  local cb = (job and job.on_event) or self.on_event
  if not cb then return end
  local payload = {
    event = event,
    id = job and job.id or nil,
    method = job and job.method or nil,
    label = job and job.label or nil,
    pending = #self.pending,
    running = self.running,
  }
  for k, v in pairs(fields or {}) do payload[k] = v end
  pcall(cb, payload)
end

function Queue:record(job, status, fields)
  if self.recent_limit <= 0 then return end
  local entry = {
    id = job.id,
    method = job.method,
    label = job.label,
    status = status,
    attempts = fields and fields.attempts or nil,
    error = fields and fields.error or nil,
    waited_ms = fields and fields.waited_ms or nil,
    finished_ms = self.now_ms(),
  }
  self.recent[#self.recent + 1] = entry
  while #self.recent > self.recent_limit do table.remove(self.recent, 1) end
end

function Queue:pace_for(method, opts)
  if opts and opts.pace_ms ~= nil then return tonumber(opts.pace_ms) or 0 end
  return tonumber(self.method_pace_ms[method]) or tonumber(self.default_pace_ms) or 0
end

function Queue:enqueue(method, fn, opts)
  assert(type(fn) == "function", "queue job must be a function")
  opts = opts or {}
  self.sequence = self.sequence + 1
  local job = {
    id = self.sequence,
    method = tostring(method or "flickr.unknown"),
    fn = fn,
    label = opts.label,
    coalesce_key = opts.coalesce_key,
    stale = opts.stale,
    pace_ms = self:pace_for(method, opts),
    max_attempts = math.max(1, tonumber(opts.max_attempts or self.default_max_attempts) or 1),
    retry_base_ms = opts.retry_base_ms ~= nil and opts.retry_base_ms or self.retry_base_ms,
    retry_max_ms = opts.retry_max_ms ~= nil and opts.retry_max_ms or self.retry_max_ms,
    rate_limit_base_ms = opts.rate_limit_base_ms ~= nil and opts.rate_limit_base_ms or self.rate_limit_base_ms,
    retryable = opts.retryable or self.retryable,
    jitter_ms = opts.jitter_ms,
    on_wait = opts.on_wait or self.on_wait,
    on_event = opts.on_event or self.on_event,
    waited_ms = 0,
  }
  self.stats.enqueued = self.stats.enqueued + 1

  if job.coalesce_key then
    for i, pending in ipairs(self.pending) do
      if pending.coalesce_key == job.coalesce_key then
        job.replaced_jobs = pending.replaced_jobs or {}
        job.replaced_jobs[#job.replaced_jobs + 1] = pending
        self.pending[i] = job
        self.stats.coalesced = self.stats.coalesced + 1
        self:emit("coalesced", job, { replaced_id = pending.id })
        return job
      end
    end
  end

  self.pending[#self.pending + 1] = job
  self:emit("enqueued", job)
  return job
end

function Queue:wait(job, ms, why, attempt)
  ms = math.floor(tonumber(ms) or 0)
  if ms <= 0 then return end
  self.stats.waited_ms = self.stats.waited_ms + ms
  self.stats.waits = self.stats.waits + 1
  if job then job.waited_ms = (job.waited_ms or 0) + ms end
  -- Lifecycle `waiting` event for all wait reasons (pace, transient, rate-limit)
  -- so a queued/running/waiting/retrying UI can show a single "waiting Ns
  -- because <why>" state. This complements `retry` (the decision to retry) and
  -- `rate-limit`/`transient` `on_wait` (the human-facing message): pace waits
  -- previously had no event at all, so a UI could not distinguish pace-throttling
  -- from a plain run. The `retry` event still fires first for retry waits.
  self:emit("waiting", job, { ms = ms, why = why, attempt = attempt })
  if job and job.on_wait then job.on_wait(ms, why, job.method, attempt) end
  sleep_ms(self.sleep_ms, ms)
end

function Queue:run_job(job)
  local attempt = 1
  while true do
    self:emit("started", job, { attempt = attempt })
    local now = self.now_ms()
    local last = self.last_started[job.method]
    if last and job.pace_ms > 0 then
      self:wait(job, job.pace_ms - (now - last), "pace", attempt)
    end
    self.last_started[job.method] = self.now_ms()
    self.stats.started = self.stats.started + 1

    -- table.pack keeps the exact return arity (including interior/trailing nils),
    -- so multi-value successes like (memberships, nil, sets) survive unpack.
    local packed = table.pack(pcall(job.fn, attempt))
    local ok = packed[1]
    -- Success convention: the job ran AND its first return value is non-nil.
    -- Flickr helpers return a truthy value (id/body/true) on success and
    -- (nil, err) on failure.
    if ok and packed[2] ~= nil then
      local out = table.pack(table.unpack(packed, 2, packed.n))
      self.stats.succeeded = self.stats.succeeded + 1
      self:record(job, "succeeded", { attempts = attempt, waited_ms = job.waited_ms })
      self:emit("succeeded", job, { attempt = attempt })
      return out
    end

    -- Failure: if pcall caught a raised error it is in slot 2; if the job ran
    -- and returned (nil, err) the message is in slot 3 (slot 2 holds the nil
    -- first return). Guarantee a non-nil message so it survives unpack.
    local err = ok and packed[3] or packed[2]
    if err == nil then err = "Flickr queue job returned no result" end
    local retry, reason = false, nil
    if attempt < job.max_attempts and job.retryable then
      retry, reason = job.retryable(err, job.method, attempt)
    end
    if retry then
      self.stats.retried = self.stats.retried + 1
      if reason == "rate-limit" then self.stats.rate_limited = self.stats.rate_limited + 1 end
      self:emit("retry", job, { attempt = attempt, reason = reason, error = err })
      self:wait(job, backoff_delay_ms(job, attempt, reason), reason or "retry", attempt)
      attempt = attempt + 1
    else
      self.stats.failed = self.stats.failed + 1
      self:record(job, "failed", { attempts = attempt, error = err, waited_ms = job.waited_ms })
      self:emit("failed", job, { attempt = attempt, error = err })
      return table.pack(nil, err)
    end
  end
end

-- A `stale`/`done` callback is user/UI code (it reaches into darktable widgets),
-- so it can raise. Never let one of those throws abort the batch or — worse —
-- leave the queue wedged with running=true. Run them under pcall.
local function safe_call(fn, ...)
  if not fn then return end
  pcall(fn, ...)
end

function Queue:finish_job(job)
  local is_stale = false
  if job.stale then
    local ok, res = pcall(job.stale)
    is_stale = ok and res and true or false
  end
  if is_stale then
    self.stats.stale = self.stats.stale + 1
    job.result = table.pack(nil, "stale Flickr queue job")
    self:record(job, "stale", { attempts = 0, error = job.result[2], waited_ms = job.waited_ms })
    self:emit("stale", job, { error = job.result[2] })
  else
    job.result = self:run_job(job)
  end
  for _, replaced in ipairs(job.replaced_jobs or {}) do
    replaced.result = job.result
    safe_call(replaced.done, unpack_result(replaced.result))
  end
  safe_call(job.done, unpack_result(job.result))
  return job.result
end

function Queue:drain()
  if self.running then return end
  self.running = true
  -- Guarantee running is cleared even if a job somehow raises past run_job's
  -- pcall, so a single failure can never permanently wedge the scheduler.
  local ok, err = pcall(function()
    while #self.pending > 0 do
      local job = table.remove(self.pending, 1)
      self:finish_job(job)
    end
  end)
  self.running = false
  if not ok then error(err) end
end

function Queue:call(method, fn, opts)
  local job = self:enqueue(method, fn, opts)
  if opts and opts.done then job.done = opts.done end
  if self.running then
    -- Reentrant call from inside a running job: run it now (synchronously,
    -- jumping the queue) and return its real result instead of leaving it
    -- pending. The job is the just-enqueued/surviving pending entry, so pull it
    -- out of pending if present and finish it directly.
    for i, pending in ipairs(self.pending) do
      if pending == job then
        table.remove(self.pending, i)
        break
      end
    end
    return unpack_result(self:finish_job(job))
  end
  self:drain()
  if job.result then return unpack_result(job.result) end
  return nil, "queued Flickr job has not run yet"
end

function Queue:pending_count()
  return #self.pending
end

function Queue:recent_results()
  return copy_list(self.recent)
end

function Queue:summary()
  local copy = {}
  for k, v in pairs(self.stats) do copy[k] = v end
  copy.pending = #self.pending
  copy.running = self.running
  return copy
end

return M
end

