local function remote_attr(body, name)
  return body and (body:match(name .. '="(.-)"') or body:match(name .. "='(.-)'")) or nil
end

local function xml_unescape(s)
  return tostring(s or "")
    :gsub("&#x(%x+);", function(h)
      local n = tonumber(h, 16)
      if not n then return "" end
      local ok, c = pcall(utf8.char, n)
      return ok and c or ""
    end)
    :gsub("&#(%d+);", function(d)
      local n = tonumber(d, 10)
      if not n then return "" end
      local ok, c = pcall(utf8.char, n)
      return ok and c or ""
    end)
    :gsub("&quot;", '"')
    :gsub("&apos;", "'")
    :gsub("&lt;", "<")
    :gsub("&gt;", ">")
    :gsub("&amp;", "&")
end

local function parse_remote_tags(body)
  local tags_block = body and body:match("<tags>(.-)</tags>") or nil
  if not tags_block then return {} end
  local tags = {}
  for raw in tags_block:gmatch("<tag[^>]-raw=\"(.-)\"[^>]*>") do
    tags[#tags + 1] = xml_unescape(raw)
  end
  for raw in tags_block:gmatch("<tag[^>]-raw='(.-)'[^>]*>") do
    tags[#tags + 1] = xml_unescape(raw)
  end
  table.sort(tags)
  return tags
end

local function parse_search_content_type(body, photo_id)
  local id = tostring(photo_id or "")
  if id == "" then return nil end
  for attrs in tostring(body or ""):gmatch("<photo%s+([^>]-)/>") do
    if remote_attr(attrs, "id") == id then
      return remote_attr(attrs, "content_type")
    end
  end
  for attrs in tostring(body or ""):gmatch("<photo%s+([^>]-)>") do
    if not attrs:match("/%s*$") and remote_attr(attrs, "id") == id then
      return remote_attr(attrs, "content_type")
    end
  end
  return nil
end

local function parse_photo_id_or_url(value)
  value = tostring(value or ""):match("^%s*(.-)%s*$")
  if value == "" then return nil end
  if value:match("^%d+$") then return value end
  return value:match("[?&]photo_id=(%d+)")
    or value:match("/photos/[^/]+/(%d+)")
    or value:match("/photo%.gne%?id=(%d+)")
    or value:match("(%d%d%d%d%d%d%d%d+)")
end

local function set_panel_photo_id_link()
  local selection = dt.gui.selection and dt.gui.selection() or {}
  if #selection ~= 1 then
    dt.print(_("Flickr: select exactly one image before setting the link."))
    return
  end
  local image = selection[1]
  local photo_id = parse_photo_id_or_url(panel_photo_id_entry.text)
  if not photo_id then
    dt.print(_("Flickr: enter a Flickr photo ID or URL first."))
    return
  end

  local acc = load_token()
  local tag_account_nsid = state.get_any_photo_id(image)
  local account_nsid = acc and acc.nsid or tag_account_nsid
  if not account_nsid or account_nsid == "" then
    dt.print(_("Flickr: log in first, or select a photo that already has a Flickr link."))
    return
  end

  local old_photo_id = state.get_photo_id(image, account_nsid)
  state.set_photo_id(image, account_nsid, photo_id)
  panel_photo_id_entry.text = ""
  panel_remote_label.label = old_photo_id
    and string.format(_("Flickr: link changed from %s to %s"), old_photo_id, photo_id)
    or string.format(_("Flickr: link set to %s"), photo_id)
  dt.print(panel_remote_label.label)
  refresh_panel(true, http.quiet_rest_available())
end

local function clear_panel_photo_id_link()
  local selection = dt.gui.selection and dt.gui.selection() or {}
  if #selection ~= 1 then
    dt.print(_("Flickr: select exactly one image before clearing the link."))
    return
  end
  local image = selection[1]
  local acc = load_token()
  local tag_account_nsid = state.get_any_photo_id(image)
  local account_nsid = tag_account_nsid or (acc and acc.nsid)
  if not account_nsid or account_nsid == "" then
    dt.print(_("Flickr: selected image has no stored Flickr link to clear."))
    return
  end
  local old_photo_id = state.get_photo_id(image, account_nsid)
  if not old_photo_id then
    dt.print(_("Flickr: selected image has no stored Flickr link to clear."))
    return
  end
  state.clear_photo_id(image, account_nsid)
  state.clear_sets(image, account_nsid)
  panel_remote_label.label = string.format(_("Flickr: local link cleared for photo %s"), old_photo_id)
  dt.print(panel_remote_label.label)
  refresh_panel(true, false)
end

function panel_sets.api_context(action)
  if (panel_current.selection_count or 0) ~= 1 then
    dt.print(string.format(_("Flickr: select exactly one published image before %s."), action))
    return nil
  end
  local image, acc, photo_id = panel_current.image, panel_current.account, panel_current.photo_id
  if not image or not photo_id then
    dt.print(_("Flickr: select a published image first."))
    return nil
  end
  if not acc then
    dt.print(_("Flickr: log in before editing albums."))
    return nil
  end
  if not album_cache_matches(acc) then clear_album_cache() end
  local api_key, api_secret = get_credentials()
  if not api_key or not api_secret then
    dt.print(_("Flickr: missing API key/secret."))
    return nil
  end
  return image, acc, photo_id, api_key, api_secret
end

function panel_sets.refresh_list()
  local acc = load_token()
  local api_key, api_secret = get_credentials()
  if not acc then
    panel_sets.status_label.label = _("log in to refresh albums")
    dt.print(_("Flickr: log in before refreshing albums."))
    return nil, "not logged in to Flickr"
  end
  if not api_key or not api_secret then
    panel_sets.status_label.label = _("missing API credentials")
    dt.print(_("Flickr: missing API key/secret."))
    return nil, "missing Flickr API key/secret"
  end
  local sets, err = refresh_album_cache_for_export(api_key, api_secret, acc)
  if not sets then
    panel_sets.status_label.label = _("album refresh failed")
    dt.print(string.format(_("Flickr: album refresh failed: %s"), tostring(err)))
    return nil, err
  end
  panel_sets.update_choices(panel_sets.input_value())
  if panel_current.image and panel_current.account then
    panel_sets_label.label = panel_sets.format_memberships(state.get_sets(panel_current.image, panel_current.account.nsid))
    panel_sets.update_current_choices(panel_current.image, panel_current.account.nsid)
  end
  panel_sets.status_label.label = string.format(_("%d album(s) loaded"), #sets)
  dt.print(string.format(_("Flickr: loaded %d album(s)"), #sets))
  return sets
end

function panel_sets.refresh_memberships()
  local image, acc, photo_id, api_key, api_secret = panel_sets.api_context(_("refreshing albums"))
  if not image then return nil end

  local memberships, err, sets = __dtrmflickr_call("flickr.photosets.getList", function()
    return rest.photosets_get_memberships(api_key, api_secret, acc, photo_id)
  end)
  if not memberships then
    panel_sets.status_label.label = _("album membership refresh failed")
    dt.print(string.format(_("Flickr: album membership refresh failed: %s"), tostring(err)))
    return nil, err
  end

  if sets then merge_album_cache(sets, acc) end
  state.clear_sets(image, acc.nsid)
  for _, item in ipairs(memberships) do
    if item.id and item.id ~= "" then state.add_set(image, acc.nsid, item.id) end
  end
  panel_sets_label.label = panel_sets.format_memberships(state.get_sets(image, acc.nsid))
  panel_sets.update_current_choices(image, acc.nsid)
  panel_sets.update_choices(panel_sets.input_value())
  panel_sets.status_label.label = string.format(_("synced %d album membership(s)"), #memberships)
  dt.print(panel_sets.status_label.label)
  return memberships
end

function panel_sets.resolve(value)
  local match, kind = find_album_match(value)
  if match then return match, kind end
  value = trim(value)
  if value:match("^%d+$") then return { id = value, title = value }, "manual-id" end
  return nil, kind
end

local function flickr_error_code(err)
  return tostring(err or ""):match("%((%d+)%)")
end

local function photoset_add_is_already_present(err)
  return flickr_error_code(err) == "3"
    and tostring(err or ""):lower():find("already in set", 1, true) ~= nil
end

local function photoset_remove_is_already_absent(err)
  return flickr_error_code(err) == "3"
    and tostring(err or ""):lower():find("not in set", 1, true) ~= nil
end

function panel_sets.add()
  local image, acc, photo_id, api_key, api_secret = panel_sets.api_context(_("adding an album"))
  if not image then return end
  if #album_cache == 0 then panel_sets.refresh_list() end
  panel_sets.search()
  local value = panel_sets.input_value()
  if value == "" then
    dt.print(_("Flickr: type an album name or ID first."))
    return
  end

  local added, errors, unresolved = 0, {}, {}
  for part in value:gmatch("[^,]+") do
    local item, kind = panel_sets.resolve(part)
    if item and item.id and item.id ~= "" then
      local ok, err = __dtrmflickr_call("flickr.photosets.addPhoto", function()
        return rest.photosets_add_photo(api_key, api_secret, acc, item.id, photo_id)
      end)
      if ok or photoset_add_is_already_present(err) then
        state.add_set(image, acc.nsid, item.id)
        added = added + 1
      else
        errors[#errors + 1] = string.format("%s: %s", tostring(item.title or item.id), tostring(err))
      end
    else
      unresolved[#unresolved + 1] = string.format("%s: %s", trim(part),
        kind == "ambiguous" and "too many matches; type more or choose from matching albums"
        or "no matching album; refresh albums or check the name")
    end
  end

  if #unresolved > 0 then
    panel_sets.status_label.label = _("choose a matching album")
    dt.print(_("Flickr: choose a matching album: ") .. table.concat(unresolved, "; "))
  elseif #errors > 0 then
    panel_sets.status_label.label = _("album add failed")
    dt.print(_("Flickr: album add failed: ") .. table.concat(errors, "; "))
  else
    panel_sets.entry.text = ""
    panel_sets.clear_choices()
    panel_sets_label.label = panel_sets.format_memberships(state.get_sets(image, acc.nsid))
    panel_sets.update_current_choices(image, acc.nsid)
    panel_sets.status_label.label = string.format(_("added to %d album(s)"), added)
    dt.print(panel_sets.status_label.label)
  end
end

function panel_sets.create()
  local image, acc, photo_id, api_key, api_secret = panel_sets.api_context(_("creating an album"))
  if not image then return end
  if #album_cache == 0 then panel_sets.refresh_list() end
  local title = trim(panel_sets.new_entry.text or "")
  if title == "" then
    dt.print(_("Flickr: type a new album title first."))
    return
  end

  local existing = find_album_exact(title)
  if existing then
    panel_sets.status_label.label = _("album already exists")
    dt.print(string.format(_("Flickr: album '%s' already exists; use add existing album."), title))
    return
  end

  -- Do NOT auto-retry album creation. flickr.photosets.create is not idempotent
  -- and has no dedupe key, so a transient timeout *after* Flickr created the set
  -- (ack lost) is indistinguishable from "never created" — a retry would make a
  -- second duplicate album with the same title. One attempt: a transient create
  -- failure is reported and the user retries. (Same policy as flickr.upload.)
  local photoset_id, err = __dtrmflickr_call("flickr.photosets.create", function()
    return rest.photosets_create(api_key, api_secret, acc, title, photo_id)
  end, { max_attempts = 1 })
  if photoset_id then
    state.add_set(image, acc.nsid, photoset_id)
    table.insert(album_cache, 1, { id = photoset_id, title = title, photos = "1" })
    panel_sets.new_entry.text = ""
    panel_sets_label.label = panel_sets.format_memberships(state.get_sets(image, acc.nsid))
    panel_sets.update_current_choices(image, acc.nsid)
    panel_sets.status_label.label = string.format(_("created album '%s'"), title)
    dt.print(panel_sets.status_label.label)
  else
    panel_sets.status_label.label = _("album create failed")
    dt.print(string.format(_("Flickr: album create failed: %s"), tostring(err)))
  end
end

function panel_sets.remove_selected()
  local image, acc, photo_id, api_key, api_secret = panel_sets.api_context(_("removing an album"))
  if not image then return end
  local set_id = panel_sets.selected_current_id()
  if not set_id or set_id == "" then
    panel_sets.status_label.label = _("albums: none recorded")
    dt.print(_("Flickr: choose a current album to remove."))
    return
  end

  local ok, err = __dtrmflickr_call("flickr.photosets.removePhoto", function()
    return rest.photosets_remove_photo(api_key, api_secret, acc, set_id, photo_id)
  end)
  local already_absent = photoset_remove_is_already_absent(err)
  if ok or already_absent then state.remove_set(image, acc.nsid, set_id) end
  panel_sets_label.label = panel_sets.format_memberships(state.get_sets(image, acc.nsid))
  panel_sets.update_current_choices(image, acc.nsid)
  if not ok and not already_absent then
    panel_sets.status_label.label = _("album remove failed")
    dt.print(string.format(_("Flickr: album remove failed: %s"), tostring(err)))
  else
    panel_sets.status_label.label = string.format(_("removed from album %s"), tostring(set_id))
    dt.print(panel_sets.status_label.label)
  end
end

local function load_remote_content_type(api_key, api_secret, acc, photo_id, dateuploaded)
  local args = {
    user_id = acc and acc.nsid or nil,
    extras = "content_type",
    per_page = 50,
    page = 1,
  }
  if dateuploaded and dateuploaded ~= "" then
    args.min_upload_date = dateuploaded
    args.max_upload_date = dateuploaded
  end

  local body, err
  if acc then
    body, err = __dtrmflickr_call("flickr.photos.search", function()
      return rest.call(api_key, api_secret, acc, "flickr.photos.search", args)
    end, { coalesce_key = "panel-refresh-content:" .. tostring(photo_id) })
  else
    body, err = __dtrmflickr_call("flickr.photos.search", function()
      return rest.public_call(api_key, "flickr.photos.search", args)
    end, { coalesce_key = "panel-refresh-content:" .. tostring(photo_id) })
  end
  local search_value = parse_search_content_type(body, photo_id)
  return panel_content_type_index_from_search_value(search_value), search_value, err
end

local function load_remote_settings(api_key, api_secret, acc, photo_id)
  panel_reset_remote(_("Flickr: loading remote settings..."))
  local body, err
  if acc then
    body, err = __dtrmflickr_call("flickr.photos.getInfo", function()
      return rest.call(api_key, api_secret, acc, "flickr.photos.getInfo", { photo_id = photo_id })
    end, { coalesce_key = "panel-refresh:" .. tostring(photo_id) })
  else
    body, err = __dtrmflickr_call("flickr.photos.getInfo", function()
      return rest.public_call(api_key, "flickr.photos.getInfo", { photo_id = photo_id })
    end, { coalesce_key = "panel-refresh:" .. tostring(photo_id) })
  end
  if not body then
    panel_reset_remote(string.format(_("Flickr: remote settings unavailable: %s"), tostring(err)))
    return
  end

  local visibility = body:match("<visibility%s+([^>]-)/>") or body:match("<visibility%s+([^>]-)>")
  panel_loading = true
  panel_privacy_widget.selected = panel_privacy_index_from_flags(
    visibility and remote_attr(visibility, "ispublic"),
    visibility and remote_attr(visibility, "isfriend"),
    visibility and remote_attr(visibility, "isfamily")) or 0
  panel_safety_widget.selected = panel_safety_index_from_remote(remote_attr(body, "safety_level")) or 0
  panel_license_widget.selected = panel_license_index_from_id(remote_attr(body, "license")) or 0
  local content_type_index = load_remote_content_type(api_key, api_secret, acc, photo_id, remote_attr(body, "dateuploaded"))
  panel_content_type_widget.selected = content_type_index or 0
  local perms_unavailable = false
  if acc then
    local perms_body, perms_err = __dtrmflickr_call("flickr.photos.getPerms", function()
      return rest.photos_get_perms(api_key, api_secret, acc, photo_id)
    end, { coalesce_key = "panel-refresh-perms:" .. tostring(photo_id) })
    if perms_body then
      panel_comment_perm_widget.selected = panel_permission_index_from_id(remote_attr(perms_body, "permcomment")) or 0
      panel_addmeta_perm_widget.selected = panel_permission_index_from_id(remote_attr(perms_body, "permaddmeta")) or 0
    else
      -- Capture and log the reason so a real perms failure is diagnosable,
      -- matching the getInfo/search read sites; the controls still disable.
      dt.print_log("[dtrmflickr] getPerms unavailable for photo " ..
        tostring(photo_id) .. ": " .. tostring(perms_err))
      panel_comment_perm_widget.selected = 0
      panel_addmeta_perm_widget.selected = 0
      perms_unavailable = true
    end
  else
    panel_comment_perm_widget.selected = 0
    panel_addmeta_perm_widget.selected = 0
  end
  local remote_tags = parse_remote_tags(body)
  panel_tags_label.label = #remote_tags > 0
    and string.format(_("Flickr tags: %s"), table.concat(remote_tags, ", "))
    or _("Flickr tags: none")
  panel_loading = false
  panel_dirty = { privacy = false, safety = false, content_type = false, license = false, comment_perm = false, addmeta_perm = false }
  panel_privacy_widget.sensitive = acc ~= nil
  panel_safety_widget.sensitive = acc ~= nil
  panel_content_type_widget.sensitive = acc ~= nil
  panel_license_widget.sensitive = acc ~= nil
  panel_comment_perm_widget.sensitive = acc ~= nil and not perms_unavailable
  panel_addmeta_perm_widget.sensitive = acc ~= nil and not perms_unavailable
  panel_current.remote_loaded = true
  panel_remote_label.label = perms_unavailable
    and _("Flickr: remote settings loaded; permissions unavailable")
    or content_type_index
    and _("Flickr: remote settings loaded")
    or _("Flickr: remote settings loaded; content type unavailable")
end

local function save_panel_settings()
  local acc, photo_id = panel_current.account, panel_current.photo_id
  if (panel_current.selection_count or 0) ~= 1 then
    dt.print(_("Flickr: select exactly one image before saving panel settings."))
    return
  end
  if not photo_id then
    dt.print(_("Flickr: select a published image first."))
    return
  end
  if not acc then
    dt.print(_("Flickr: log in from Lua Options before saving Flickr settings."))
    return
  end
  if not panel_current.remote_loaded then
    dt.print(_("Flickr: remote settings are not loaded yet."))
    return
  end
  local api_key, api_secret = get_credentials()
  if not api_key or not api_secret then
    dt.print(_("Flickr: missing API key/secret."))
    return
  end

  local errors = {}
  local skipped = {}
  local saved_fields = {}
  local sync = master_sync_fields()
  local is_public, is_friend, is_family = panel_privacy_flags()
  local wants_privacy = panel_dirty.privacy
  local wants_comment_perm = panel_dirty.comment_perm
  local wants_addmeta_perm = panel_dirty.addmeta_perm
  local update_privacy = wants_privacy and sync.privacy
  local update_comment_perm = wants_comment_perm and sync.permissions
  local update_addmeta_perm = wants_addmeta_perm and sync.permissions
  if update_privacy or update_comment_perm or update_addmeta_perm then
    local ok, err = __dtrmflickr_call("flickr.photos.setPerms", function()
      return rest.photos_set_perms(api_key, api_secret, acc, photo_id, is_public, is_friend, is_family,
        update_comment_perm and panel_comment_perm_value() or nil,
        update_addmeta_perm and panel_addmeta_perm_value() or nil)
    end)
    if not ok then
      if update_privacy then state.mark_reason(panel_current.image, acc.nsid, "visibility") end
      if update_comment_perm or update_addmeta_perm then state.mark_reason(panel_current.image, acc.nsid, "permissions") end
      errors[#errors + 1] = "privacy: " .. tostring(err)
    else
      if update_privacy then state.clear_reason(panel_current.image, acc.nsid, "visibility") end
      if update_comment_perm or update_addmeta_perm then state.clear_reason(panel_current.image, acc.nsid, "permissions") end
      if update_privacy then saved_fields[#saved_fields + 1] = "visibility" end
      if update_comment_perm or update_addmeta_perm then saved_fields[#saved_fields + 1] = "permissions" end
    end
  end
  if wants_privacy and not sync.privacy then skipped[#skipped + 1] = "privacy" end
  if (wants_comment_perm or wants_addmeta_perm) and not sync.permissions then
    skipped[#skipped + 1] = "permissions"
  end
  local safety = panel_safety_value()
  if panel_dirty.safety and sync.safety then
    local ok, err = __dtrmflickr_call("flickr.photos.setSafetyLevel", function()
      return rest.photos_set_safety_level(api_key, api_secret, acc, photo_id, safety)
    end)
    if not ok then
      state.mark_reason(panel_current.image, acc.nsid, "safety")
      errors[#errors + 1] = "safety: " .. tostring(err)
    else
      state.clear_reason(panel_current.image, acc.nsid, "safety")
      saved_fields[#saved_fields + 1] = "safety"
    end
  elseif panel_dirty.safety then
    skipped[#skipped + 1] = "safety"
  end
  local content_type = panel_content_type_value()
  if panel_dirty.content_type and sync.content_type then
    if content_type then
      local ok, err = __dtrmflickr_call("flickr.photos.setContentType", function()
        return rest.photos_set_content_type(api_key, api_secret, acc, photo_id, content_type)
      end)
      if not ok then
        state.mark_reason(panel_current.image, acc.nsid, "content_type")
        errors[#errors + 1] = "content type: " .. tostring(err)
      else
        state.clear_reason(panel_current.image, acc.nsid, "content_type")
        saved_fields[#saved_fields + 1] = "content_type"
      end
    else
      errors[#errors + 1] = "content type: choose a value first"
    end
  elseif panel_dirty.content_type then
    skipped[#skipped + 1] = "content type"
  end
  local license = panel_license_value()
  if panel_dirty.license and sync.license then
    local ok, err = __dtrmflickr_call("flickr.photos.licenses.setLicense", function()
      return rest.photos_licenses_set_license(api_key, api_secret, acc, photo_id, license)
    end)
    if not ok then
      state.mark_reason(panel_current.image, acc.nsid, "license")
      errors[#errors + 1] = "license: " .. tostring(err)
    else
      state.clear_reason(panel_current.image, acc.nsid, "license")
      saved_fields[#saved_fields + 1] = "license"
    end
  elseif panel_dirty.license then
    skipped[#skipped + 1] = "license"
  end

  if #errors > 0 then
    panel_remote_label.label = _("Flickr: save failed")
    dt.print(_("Flickr: save failed: ") .. table.concat(errors, "; "))
  elseif #skipped > 0 then
    if #saved_fields > 0 then
      state.set_metadata_published_at(panel_current.image, acc.nsid)
      store_metadata_fingerprints(panel_current.image, acc.nsid,
        effective_metadata_fingerprints(panel_current.image, sync), saved_fields)
      panel_sets.refresh_publish_state_label(panel_current.image, acc, photo_id)
    end
    panel_remote_label.label = _("Flickr: settings skipped by Lua sync options")
    dt.print(_("Flickr: settings skipped by Lua sync options: ") .. table.concat(skipped, ", "))
  else
    state.set_metadata_published_at(panel_current.image, acc.nsid)
    store_metadata_fingerprints(panel_current.image, acc.nsid,
      effective_metadata_fingerprints(panel_current.image, sync), saved_fields)
    panel_sets.refresh_publish_state_label(panel_current.image, acc, photo_id)
    panel_remote_label.label = _("Flickr: settings saved")
    dt.print(_("Flickr: settings saved."))
    load_remote_settings(api_key, api_secret, acc, photo_id)
  end
end

local function sync_panel_meta()
  local acc, photo_id, image = panel_current.account, panel_current.photo_id, panel_current.image
  if (panel_current.selection_count or 0) ~= 1 then
    dt.print(_("Flickr: select exactly one image before syncing metadata."))
    return
  end
  if not image or not photo_id then
    dt.print(_("Flickr: select a published image first."))
    return
  end
  if not acc then
    dt.print(_("Flickr: log in from Lua Options before syncing Flickr metadata."))
    return
  end
  local api_key, api_secret = get_credentials()
  if not api_key or not api_secret then
    dt.print(_("Flickr: missing API key/secret."))
    return
  end

  local sync = master_sync_fields()
  local title = sync.title and (image and image.title or "") or nil
  local description = sync.description and (image and image.description or "") or nil
  if not sync.title and not sync.description then
    dt.print(_("Flickr: title/description sync disabled in Lua Options."))
    return
  end
  if title == nil and description == nil then
    dt.print(_("Flickr: selected image has no title or description to sync."))
    return
  end

  local ok, err = __dtrmflickr_call("flickr.photos.setMeta", function()
    return rest.photos_set_meta(api_key, api_secret, acc, photo_id, title, description)
  end)
  if ok then
    state.set_metadata_published_at(image, acc.nsid)
    state.clear_reason(image, acc.nsid, "title_description")
    store_metadata_fingerprints(image, acc.nsid,
      effective_metadata_fingerprints(image, master_sync_fields()), { "title_description" })
    panel_sets.refresh_publish_state_label(image, acc, photo_id)
    panel_remote_label.label = _("Flickr: title/description synced")
    dt.print(_("Flickr: title/description synced."))
    load_remote_settings(api_key, api_secret, acc, photo_id)
  else
    state.mark_reason(image, acc.nsid, "title_description")
    panel_remote_label.label = _("Flickr: metadata sync failed")
    dt.print(_("Flickr: metadata sync failed: ") .. tostring(err))
  end
end

local function sync_panel_tags()
  local acc, photo_id, image = panel_current.account, panel_current.photo_id, panel_current.image
  if (panel_current.selection_count or 0) ~= 1 then
    dt.print(_("Flickr: select exactly one image before syncing keywords."))
    return
  end
  if not image or not photo_id then
    dt.print(_("Flickr: select a published image first."))
    return
  end
  if not acc then
    dt.print(_("Flickr: log in from Lua Options before syncing Flickr keywords."))
    return
  end
  local api_key, api_secret = get_credentials()
  if not api_key or not api_secret then
    dt.print(_("Flickr: missing API key/secret."))
    return
  end
  if not master_sync_fields().tags then
    dt.print(_("Flickr: keyword sync disabled in Lua Options."))
    return
  end

  local tags, truncated_tags = rules.image_keyword_tags(image)
  tags = tags or ""
  if truncated_tags and truncated_tags > 0 then
    dt.print(string.format(_("Flickr: selected image has more than %d publishable keywords; skipped %d extra tag(s)"),
      FLICKR_TAG_LIMIT, truncated_tags))
  end

  -- setTags is a full *replace* of the tag set, which is idempotent for a fixed
  -- input: replaying it on a lost-ack retry converges to the same tags. So,
  -- unlike upload/photosets.create, it keeps the default retry/backoff.
  local ok, err = __dtrmflickr_call("flickr.photos.setTags", function()
    return rest.photos_set_tags(api_key, api_secret, acc, photo_id, tags)
  end)
  if ok then
    state.set_metadata_published_at(image, acc.nsid)
    state.clear_reason(image, acc.nsid, "keywords")
    store_metadata_fingerprints(image, acc.nsid,
      effective_metadata_fingerprints(image, master_sync_fields()), { "keywords" })
    panel_sets.refresh_publish_state_label(image, acc, photo_id)
    panel_remote_label.label = _("Flickr: keywords synced")
    dt.print(_("Flickr: keywords synced."))
    load_remote_settings(api_key, api_secret, acc, photo_id)
  else
    state.mark_reason(image, acc.nsid, "keywords")
    panel_remote_label.label = _("Flickr: keyword sync failed")
    dt.print(_("Flickr: keyword sync failed: ") .. tostring(err))
  end
end

local function publish_state_label(status, published_at, reasons)
  local suffix = published_at and (" (" .. published_at .. ")") or ""
  if reasons and #reasons > 0 then
    suffix = suffix .. ": " .. table.concat(reasons, ", ")
  end
  if status == "current" then
    return string.format(_("publish state: current%s"), suffix)
  elseif status == "needs-republish" then
    local kind = state.classify_reasons and state.classify_reasons(reasons) or "none"
    if kind == "image" then
      return string.format(_("publish state: needs reupload%s"), suffix)
    elseif kind == "metadata" then
      return string.format(_("publish state: needs metadata sync%s"), suffix)
    elseif kind == "both" then
      return string.format(_("publish state: needs reupload + metadata sync%s"), suffix)
    end
    return string.format(_("publish state: needs sync%s"), suffix)
  elseif status == "unknown" then
    return _("publish state: linked, sync date unknown")
  elseif status == "unpublished" then
    return _("publish state: unpublished")
  end
  return _("publish state: unknown")
end

function panel_sets.refresh_publish_state_label(image, acc, photo_id)
  if not image or not photo_id then
    panel_sets.publish_label.label = publish_state_label("unpublished")
    return "unpublished"
  end
  if not acc then
    panel_sets.publish_label.label = _("publish state: log in to evaluate")
    return "unknown"
  end
  local status, published_at, _photo_id, reasons = state.evaluate_publish_state(image, acc.nsid, {
    metadata_fingerprints = effective_metadata_fingerprints and effective_metadata_fingerprints(image, master_sync_fields()) or nil,
  })
  panel_sets.publish_label.label = publish_state_label(status, published_at, reasons)
  return status, published_at, reasons
end

function panel_sets.mark_needs_republish()
  local acc, photo_id, image = panel_current.account, panel_current.photo_id, panel_current.image
  if (panel_current.selection_count or 0) ~= 1 then
    dt.print(_("Flickr: select exactly one image before marking sync state."))
    return
  end
  if not image or not photo_id then
    dt.print(_("Flickr: select a published image first."))
    return
  end
  if not acc then
    dt.print(_("Flickr: log in from Lua Options before marking sync state."))
    return
  end
  state.mark_reason(image, acc.nsid, "image")
  panel_sets.publish_label.label = publish_state_label("needs-republish", state.get_published_at(image, acc.nsid), state.get_reasons(image, acc.nsid))
  dt.print(_("Flickr: marked selected photo as needing sync."))
end

function panel_sets.clear_needs_republish()
  local acc, photo_id, image = panel_current.account, panel_current.photo_id, panel_current.image
  if (panel_current.selection_count or 0) ~= 1 then
    dt.print(_("Flickr: select exactly one image before clearing sync state."))
    return
  end
  if not image or not photo_id then
    dt.print(_("Flickr: select a published image first."))
    return
  end
  if not acc then
    dt.print(_("Flickr: log in from Lua Options before clearing sync state."))
    return
  end
  state.set_published_at(image, acc.nsid, image.change_timestamp or nil)
  panel_sets.refresh_publish_state_label(image, acc, photo_id)
  dt.print(_("Flickr: cleared selected photo's needs-sync marker."))
end

function panel_sets.scan_selected_publish_state()
  local selection = dt.gui.selection and dt.gui.selection() or {}
  if #selection == 0 then
    dt.print(_("Flickr: select one or more images before scanning sync state."))
    return
  end
  local acc = load_token()
  if not acc then
    dt.print(_("Flickr: log in from Lua Options before scanning sync state."))
    return
  end
  local counts = { ["needs-republish"] = 0, current = 0, unknown = 0, unpublished = 0 }
  local sync = master_sync_fields()
  for _, image in ipairs(selection) do
    local status = state.evaluate_publish_state(image, acc.nsid, {
      metadata_fingerprints = effective_metadata_fingerprints and effective_metadata_fingerprints(image, sync) or nil,
    })
    counts[status] = (counts[status] or 0) + 1
  end
  refresh_panel(true, false)
  dt.print(string.format(_("Flickr: scanned %d selected photo(s): %d need sync, %d current, %d unknown, %d unpublished"),
    #selection, counts["needs-republish"] or 0, counts.current or 0, counts.unknown or 0, counts.unpublished or 0))
end

local function claim_existing_selection()
  local selection = dt.gui.selection and dt.gui.selection() or {}
  if #selection == 0 then
    dt.print(_("Flickr: select one or more images to claim existing Flickr photos."))
    return
  end
  local acc = load_token()
  if not acc then
    dt.print(_("Flickr: log in before claiming existing photos."))
    return
  end
  local api_key, api_secret = get_credentials()
  if not api_key or not api_secret then
    dt.print(_("Flickr: missing API key/secret."))
    return
  end

  local counts = { claimed = 0, skipped = 0, error = 0 }
  for _index, image in ipairs(selection) do
    local status, detail = __dtrmflickr_call("flickr.photos.search", function()
      return claim.claim_existing_for_image(api_key, api_secret, acc, image)
    end)
    -- The queue returns (nil, err) when a transient claim search exhausted its
    -- retries; treat that as an error rather than indexing counts[nil].
    if status == nil then status = "error" end
    counts[status] = (counts[status] or 0) + 1
    local file = image and image.filename or "image"
    if status == "claimed" then
      dt.print(string.format(_("Flickr: linked %s to photo %s"), file, detail))
    elseif status == "error" then
      dt.print(string.format(_("Flickr: could not search %s: %s"), file, detail))
    else
      dt.print(string.format(_("Flickr: skipped %s: %s"), file, detail))
    end
  end
  panel_remote_label.label = string.format(_("Flickr: claim existing done (%d linked, %d skipped, %d error(s))"),
    counts.claimed or 0, counts.skipped or 0, counts.error or 0)
  refresh_panel(true)
end

function refresh_panel(force, fetch_remote)
  if not force and not panel_is_visible() then return end
  fetch_remote = fetch_remote == true

  local selection = dt.gui.selection and dt.gui.selection() or {}
  local image = selection[1]
  panel_current = { image = image, account = nil, photo_id = nil, selection_count = #selection, remote_loaded = false }
  if not image then
    panel_sets.update_photo_link_buttons(selection, nil, nil)
    panel_status_label.label = _("no image selected")
    panel_file_label.label = ""
    panel_account_label.label = ""
    panel_photo_label.label = ""
    panel_sets.publish_label.label = ""
    panel_sets_label.label = ""
    panel_sets.status_label.label = ""
    panel_sets.clear_current_choices()
    panel_reset_remote("")
    return
  end

  local acc = load_token()
  local count_suffix = #selection > 1 and string.format(_(" (+%d more selected)"), #selection - 1) or ""
  panel_status_label.label = _("selected") .. count_suffix
  panel_file_label.label = string.format(_("file: %s"), image.filename or "?")

  if not acc then
    local tag_account_nsid, tagged_photo_id = state.get_any_photo_id(image)
    panel_current = { image = image, account = nil, photo_id = tagged_photo_id, selection_count = #selection, remote_loaded = false }
    panel_sets.update_photo_link_buttons(selection, nil, tagged_photo_id)
    panel_account_label.label = tag_account_nsid
      and string.format(_("account: %s (not logged in)"), tag_account_nsid)
      or _("account: not logged in")
    panel_photo_label.label = tagged_photo_id
      and string.format(_("photo: %s"), tagged_photo_id)
      or _("photo: not published")
    panel_sets.refresh_publish_state_label(image, nil, tagged_photo_id)
    panel_sets_label.label = ""
    panel_sets.clear_current_choices()
    if not tagged_photo_id then
      panel_reset_remote(_("Flickr: no stored photo ID tag; nothing to fetch"))
      return
    end
    if not fetch_remote then
      panel_reset_remote(_("Flickr: stored photo ID tag found; click refresh to load remote settings"))
      return
    end
    local api_key = dt.preferences.read(PLUGIN, "api_key", "string")
    if not api_key or api_key == "" then
      panel_reset_remote(_("Flickr: API key required for public photo info"))
      return
    end
    load_remote_settings(api_key, nil, nil, tagged_photo_id)
    return
  end

  local photo_id = state.get_photo_id(image, acc.nsid)
  local sets = state.get_sets(image, acc.nsid)
  panel_current = { image = image, account = acc, photo_id = photo_id, selection_count = #selection, remote_loaded = false }
  panel_sets.update_photo_link_buttons(selection, acc, photo_id)
  panel_account_label.label = string.format(_("account: %s"), acc.username or acc.nsid)
  panel_photo_label.label = photo_id
    and string.format(_("photo: %s"), photo_id)
    or _("photo: not published")
  panel_sets.refresh_publish_state_label(image, acc, photo_id)
  panel_sets_label.label = panel_sets.format_memberships(sets)
  panel_sets.update_current_choices(image, acc.nsid)
  if not photo_id then
    panel_reset_remote(_("Flickr: no stored photo ID; nothing to fetch"))
    return
  end
  if not fetch_remote then
    panel_reset_remote(_("Flickr: stored photo ID found; click refresh to load remote settings"))
    return
  end

  local api_key, api_secret = get_credentials()
  if api_key and api_secret then
    load_remote_settings(api_key, api_secret, acc, photo_id)
  else
    panel_reset_remote(_("Flickr: missing API key/secret"))
  end
end

